   637→// Analyze speech transcription for communication quality
   638→function analyzeSpeechPatterns(transcription, durationSeconds) {
   639→  const words = transcription.trim().split(/\s+/).filter(w => w.length > 0);
   640→  const wordCount = words.length;
   641→  const wpm = durationSeconds > 0 ? Math.round((wordCount / durationSeconds) * 60) : 0;
   642→
   643→  // Filler word detection
   644→  const fillerWords = ['um', 'uh', 'like', 'you know', 'so', 'basically', 'actually', 'literally', 'right', 'okay so', 'i mean'];
   645→  const fillerCounts = {};
   646→  let totalFillers = 0;
   647→  const lowerTranscription = transcription.toLowerCase();
   648→
   649→  for (const filler of fillerWords) {
   650→    const regex = new RegExp(`\\b${filler}\\b`, 'gi');
   651→    const matches = lowerTranscription.match(regex);
   652→    if (matches && matches.length > 0) {
   653→      fillerCounts[filler] = matches.length;
   654→      totalFillers += matches.length;
   655→    }
   656→  }
   657→
   658→  const fillerRate = wordCount > 0 ? (totalFillers / wordCount) * 100 : 0;
   659→
   660→  // Pace analysis
   661→  let paceAssessment = 'good';
   662→  let paceFeedback = '';
   663→  if (wpm < 100) {
   664→    paceAssessment = 'too_slow';
   665→    paceFeedback = 'Your speaking pace is quite slow. Try to speak more naturally and with more energy. Aim for 120-150 words per minute.';
   666→  } else if (wpm < 120) {
   667→    paceAssessment = 'slightly_slow';
   668→    paceFeedback = 'Your pace is a bit slow. Try to increase your speaking speed slightly for more engaging delivery.';
   669→  } else if (wpm <= 160) {
   670→    paceAssessment = 'good';
   671→    paceFeedback = 'Your speaking pace is natural and easy to follow. Well done!';
   672→  } else if (wpm <= 180) {
   673→    paceAssessment = 'slightly_fast';
   674→    paceFeedback = 'You\'re speaking a bit quickly. Try to slow down slightly and pause between key points.';
   675→  } else {
   676→    paceAssessment = 'too_fast';
   677→    paceFeedback = 'You\'re speaking too fast — this can signal nervousness. Take deliberate pauses between sentences and breathe.';
   678→  }
   679→
   680→  // Sentence structure analysis
   681→  const sentences = transcription.split(/[.!?]+/).filter(s => s.trim().length > 0);
   682→  const avgSentenceLength = sentences.length > 0 ? Math.round(wordCount / sentences.length) : 0;
   683→
   684→  // Communication score (1-10)
   685→  let communicationScore = 7;
   686→  // Penalize for filler words
   687→  if (fillerRate > 5) communicationScore -= 2;
   688→  else if (fillerRate > 3) communicationScore -= 1;
   689→  // Penalize for bad pace
   690→  if (paceAssessment === 'too_slow' || paceAssessment === 'too_fast') communicationScore -= 1.5;
   691→  else if (paceAssessment === 'slightly_slow' || paceAssessment === 'slightly_fast') communicationScore -= 0.5;
   692→  // Reward for good sentence structure
   693→  if (avgSentenceLength >= 10 && avgSentenceLength <= 25) communicationScore += 0.5;
   694→  // Penalize for very short responses
   695→  if (wordCount < 50) communicationScore -= 2;
   696→  else if (wordCount < 100) communicationScore -= 1;
   697→  // Reward for substantial responses
   698→  if (wordCount >= 150 && wordCount <= 400) communicationScore += 0.5;
   699→
   700→  communicationScore = Math.max(1, Math.min(10, Math.round(communicationScore * 10) / 10));
   701→
   702→  return {
   703→    word_count: wordCount,
   704→    duration_seconds: durationSeconds,
   705→    words_per_minute: wpm,
   706→    filler_words: fillerCounts,
   707→    total_fillers: totalFillers,
   708→    filler_rate: Math.round(fillerRate * 10) / 10,
   709→    pace: {
   710→      assessment: paceAssessment,
   711→      wpm,
   712→      feedback: paceFeedback
   713→    },
   714→    sentence_count: sentences.length,
   715→    avg_sentence_length: avgSentenceLength,
   716→    communication_score: communicationScore,
   717→    tips: generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts)
   718→  };
   719→}
   720→
   721→function generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts) {
   722→  const tips = [];
   723→
   724→  if (fillerRate > 3) {
   725→    const topFillers = Object.entries(fillerCounts)
   726→      .sort((a, b) => b[1] - a[1])
   727→      .slice(0, 3)
   728→      .map(([word, count]) => `"${word}" (${count}x)`);
   729→    tips.push(`Reduce filler words — you used ${totalFillers} fillers: ${topFillers.join(', ')}. Try pausing silently instead.`);
   730→  }
   731→
   732→  if (wpm > 160) {
   733→    tips.push('Slow down your pace. Take a breath between key points to let your message land.');
   734→  } else if (wpm < 110) {
   735→    tips.push('Pick up the pace slightly. A faster tempo projects confidence and engagement.');
   736→  }
   737→
   738→  if (wordCount < 80) {
   739→    tips.push('Your response was quite short. Aim for 1-2 minutes of speaking time to give a comprehensive answer.');
   740→  }
   741→
   742→  if (tips.length === 0) {
   743→    tips.push('Strong verbal delivery! Your pace and clarity are good. Keep practicing to maintain consistency.');
   744→  }
   745→
   746→  return tips;
   747→}
