  1089→// AI interviewer conducts a conversational interview turn
  1090→async function conductInterviewTurn(conversation, baseQuestions, currentQuestionIndex, targetRole, options = {}) {
  1091→  // Send last 12 turns for better context on follow-ups
  1092→  const recentConvo = conversation.slice(-12);
  1093→  const convoText = recentConvo.map(turn => {
  1094→    if (turn.role === 'interviewer') return `INTERVIEWER: ${turn.text}`;
  1095→    return `CANDIDATE: ${turn.text}`;
  1096→  }).join('\n\n');
  1097→
  1098→  const candidateTurnCount = conversation.filter(t => t.role === 'candidate').length;
  1099→  const followUpCount = conversation.filter(t => t.role === 'interviewer' && (t.action === 'follow_up' || t.action === 'challenge')).length;
  1100→  const remainingQuestions = baseQuestions.slice(currentQuestionIndex);
  1101→  const nextPlannedQuestion = remainingQuestions.length > 0
  1102→    ? remainingQuestions[0].question_text
  1103→    : null;
  1104→
  1105→  // Count consecutive follow-ups on the current topic
  1106→  let consecutiveFollowUps = 0;
  1107→  for (let i = conversation.length - 1; i >= 0; i--) {
  1108→    const t = conversation[i];
  1109→    if (t.role === 'interviewer' && (t.action === 'follow_up' || t.action === 'challenge')) {
  1110→      consecutiveFollowUps++;
  1111→    } else if (t.role === 'interviewer' && t.action === 'transition') {
  1112→      break;
  1113→    } else if (t.role === 'candidate') {
  1114→      continue; // skip candidate turns when counting
  1115→    }
  1116→  }
  1117→
  1118→  const prompt = `You are conducting a mock interview for a "${targetRole}" position. You have ${remainingQuestions.length} planned questions remaining.
  1119→
  1120→CONVERSATION SO FAR:
  1121→${convoText}
  1122→
  1123→${nextPlannedQuestion ? `NEXT PLANNED QUESTION (use when ready to move on): "${nextPlannedQuestion}"` : 'All planned questions covered.'}
  1124→
  1125→FOLLOW-UP COUNT on current topic: ${consecutiveFollowUps}
  1126→
  1127→YOUR TASK: Act like a real interviewer. After the candidate answers:
  1128→
  1129→1. **FOLLOW UP** if the answer is:
  1130→   - Vague or surface-level ("I worked on a project" → ask WHAT project, what was the challenge)
  1131→   - Missing specifics (no metrics, no concrete examples, no details about their role)
  1132→   - Interesting but unexplored (they mentioned something worth digging into)
  1133→   - Missing the "so what" (they described what happened but not the impact/result)
  1134→   You can ask MULTIPLE follow-ups on the same topic. Keep probing until you have real depth.
  1135→
  1136→2. **TRANSITION** to the next planned question when:
  1137→   - The candidate gave a thorough, specific answer with concrete examples
  1138→   - You've already asked 2-3 follow-ups and have sufficient depth
  1139→   - The candidate clearly has nothing more to add on this topic
  1140→
  1141→3. **WRAP UP** when: ${candidateTurnCount >= 6 ? 'You feel you have enough data (6+ exchanges completed)' : 'NOT YET — keep interviewing, only ' + candidateTurnCount + ' exchanges so far'}
  1142→
  1143→React to their answer specifically (1-2 sentences — reference something concrete they said, NOT generic filler like "Thank you for that response" or "That's helpful"). Show you actually listened. Example good reactions: "That 40% improvement in pipeline throughput is impressive — how did you measure that?" or "Interesting that you chose to refactor first rather than ship the feature." Example bad reactions: "Thank you for sharing that." or "That's great, thanks."
  1144→
  1145→Return JSON: {"reaction":"1-2 sentences referencing SPECIFIC details from their answer","action":"follow_up|challenge|transition|wrap_up","question":"your next question","score_hint":1-10,"notes":"brief note on answer quality"}`;
  1146→
  1147→  const result = await chat(prompt, {
  1148→    system: `You are Alex, an experienced ${targetRole} interviewer. You conduct interviews like a real person — curious, attentive, and thorough. You don't just read from a script. When a candidate gives a vague answer, you probe deeper. When they mention something interesting, you explore it. You ask follow-up questions naturally, like "Tell me more about that" or "What specifically was your role in that?" or "How did you measure success?" You only move to the next planned question when you're genuinely satisfied with the depth of their answer. Always return valid JSON only.`,
  1149→    maxTokens: 1024,
  1150→    subscriptionId: options.subscriptionId,
  1151→    module: 'mock_interview', feature: 'interview_turn'
  1152→  });
  1153→
  1154→  const parsed = safeParseJSON(result);
  1155→  if (parsed) return parsed;
  1156→  throw new Error('Failed to generate interview turn — could not parse LLM response');
  1157→}
